import (
	"context"
	"github.com/openmeterio/openmeter/openmeter/billing/charges/creditpurchase"
	dbchargecreditpurchase "github.com/openmeterio/openmeter/openmeter/ent/db/chargecreditpurchase"
	"github.com/openmeterio/openmeter/pkg/framework/entutils"
)

func (a *adapter) SomeUpdate(ctx context.Context, in creditpurchase.SomeInput) (creditpurchase.SomeResult, error) {
	if err := in.Validate(); err != nil {
		return creditpurchase.SomeResult{}, err
	}
	return entutils.TransactingRepo(ctx, a, func(ctx context.Context, tx *adapter) (creditpurchase.SomeResult, error) {
		entity, err := tx.db.ChargeCreditPurchase.UpdateOneID(in.ID).
			Where(dbchargecreditpurchase.NamespaceEQ(in.Namespace)).
			Save(ctx)
		if err != nil {
			return creditpurchase.SomeResult{}, err
		}
		return MapSomeResultFromDB(entity), nil
	})
}

import (
	"context"
	"fmt"
	"github.com/openmeterio/openmeter/openmeter/billing"
	"github.com/openmeterio/openmeter/openmeter/billing/service/invoicecalc"
)

func (e *Engine) CalculateLines(input billing.CalculateLinesInput) (billing.StandardLines, error) {
	for _, stdLine := range input.Lines {
		if stdLine.ChargeID == nil {
			return nil, fmt.Errorf("credit purchase standard line[%s]: charge id is required", stdLine.ID)
		}
		generated, err := e.ratingService.GenerateDetailedLines(stdLine)
		if err != nil {
			return nil, fmt.Errorf("generating detailed lines for line[%s]: %w", stdLine.ID, err)
		}
		if err := invoicecalc.MergeGeneratedDetailedLines(stdLine, generated); err != nil {
			return nil, fmt.Errorf("merging detailed lines for line[%s]: %w", stdLine.ID, err)
		}
	}
	return input.Lines, nil
}

